function isSameModelFamily(first, second) {
  if (!first || !second) {
    return false;
  }

  // Use top-level vendor family (claude vs gpt) so that all Claude sub-models
  // (haiku, sonnet, opus) are treated as the same family, and all GPT variants
  // (including codex) are treated as the same family. This correctly implements
  // the diversity-of-thought rule: prefer a different *vendor* family for review,
  // not merely a different sub-model within the same vendor.
  const topFamily = (model) => {
    if (model.startsWith("claude-")) return "claude";
    if (model.startsWith("gpt-")) return "gpt";
    return model;
  };

  return topFamily(first) === topFamily(second);
}

