/**
 * Lightweight regression tests for the routing policy module.
 * Run with: node --test .github/extensions/model-router/policy.test.mjs
 *
 * These tests guard the three main sources of drift:
 *  1. MODEL_FAMILIES staying in sync with MODEL_CANDIDATES
 *  2. No duplicate model IDs in a single tier
 *  3. ORCHESTRATION_KEYWORDS being a non-empty array of multi-token strings
 */
import { describe, it } from "node:test";
import assert from "node:assert/strict";
import {
  MODEL_CANDIDATES,
  MODEL_FAMILIES,
  ORCHESTRATION_KEYWORDS,
} from "./policy.mjs";

describe("MODEL_CANDIDATES", () => {
  it("defines the three expected tiers", () => {
    assert.deepEqual(Object.keys(MODEL_CANDIDATES).sort(), [
      "builder",
      "economy",
      "reasoning",
    ]);
  });

  it("every entry has a non-empty string id", () => {
    for (const [tier, entries] of Object.entries(MODEL_CANDIDATES)) {
      for (const entry of entries) {
        assert.ok(
          typeof entry.id === "string" && entry.id.length > 0,
          `${tier} entry is missing a valid id: ${JSON.stringify(entry)}`
        );
      }
    }
  });

  it("no duplicate model id within a single tier", () => {
    for (const [tier, entries] of Object.entries(MODEL_CANDIDATES)) {
      const seen = new Set();
      for (const { id } of entries) {
        assert.ok(
          !seen.has(id),
          `Duplicate id "${id}" in tier "${tier}"`
        );
        seen.add(id);
      }
    }
  });

  it("reasoningEffort values are valid when present", () => {
    const valid = new Set(["low", "medium", "high"]);
    for (const [tier, entries] of Object.entries(MODEL_CANDIDATES)) {
      for (const entry of entries) {
        if (entry.reasoningEffort !== undefined) {
          assert.ok(
            valid.has(entry.reasoningEffort),
            `Invalid reasoningEffort "${entry.reasoningEffort}" for model "${entry.id}" in tier "${tier}"`
          );
        }
      }
    }
  });
});

describe("MODEL_FAMILIES", () => {
  it("is derived from MODEL_CANDIDATES — every candidate id appears in a family", () => {
    const allCandidateIds = Object.values(MODEL_CANDIDATES)
      .flat()
      .map((e) => e.id);

    const allFamilyIds = new Set([
      ...MODEL_FAMILIES.claude,
      ...MODEL_FAMILIES.gpt,
    ]);

    for (const id of allCandidateIds) {
      assert.ok(
        allFamilyIds.has(id),
        `Model "${id}" is in MODEL_CANDIDATES but missing from MODEL_FAMILIES`
      );
    }
  });

  it("no model id belongs to both claude and gpt families", () => {
    for (const id of MODEL_FAMILIES.claude) {
      assert.ok(
        !MODEL_FAMILIES.gpt.has(id),
        `Model "${id}" is in both claude and gpt families`
      );
    }
  });

  it("claude family contains only claude- prefixed ids", () => {
    for (const id of MODEL_FAMILIES.claude) {
      assert.ok(
        id.startsWith("claude-"),
        `Non-claude id "${id}" found in claude family`
      );
    }
  });

  it("gpt family contains only gpt- prefixed ids", () => {
    for (const id of MODEL_FAMILIES.gpt) {
      assert.ok(
        id.startsWith("gpt-"),
        `Non-gpt id "${id}" found in gpt family`
      );
    }
  });
});

describe("ORCHESTRATION_KEYWORDS", () => {
  it("is a non-empty array", () => {
    assert.ok(Array.isArray(ORCHESTRATION_KEYWORDS));
    assert.ok(ORCHESTRATION_KEYWORDS.length > 0);
  });

  it("every entry is a multi-token string (guards against re-adding bare single words)", () => {
    for (const kw of ORCHESTRATION_KEYWORDS) {
      assert.ok(
        typeof kw === "string" && /\s/.test(kw),
        `Orchestration keyword "${kw}" must contain a space — bare single words cause false positives`
      );
    }
  });

  it("does not include bare 'orchestrate' or 'orchestration' (known false-positive triggers)", () => {
    assert.ok(
      !ORCHESTRATION_KEYWORDS.includes("orchestrate"),
      'Bare "orchestrate" must not be in ORCHESTRATION_KEYWORDS'
    );
    assert.ok(
      !ORCHESTRATION_KEYWORDS.includes("orchestration"),
      'Bare "orchestration" must not be in ORCHESTRATION_KEYWORDS'
    );
  });
});

