/**
 * Model routing policy — single source of truth.
 *
 * MODEL_CANDIDATES is the authoritative runtime data. Everything else—
 * MODEL_FAMILIES, routing-matrix.md tables, and the README Model Coverage
 * section—is derived from or mirrors this object. Update here first, then
 * reflect the change in the human-readable documents.
 *
 * This module is pure (no SDK imports, no side effects) so it can be
 * imported by both extension.mjs and the test suite.
 */

// ---------------------------------------------------------------------------
// Tier definitions
// ---------------------------------------------------------------------------

export const MODEL_CANDIDATES = {
  economy: [
    { id: "claude-haiku-4.5" },
    { id: "gpt-4.1" },
    { id: "gpt-5-mini", reasoningEffort: "low" },
    { id: "gpt-5.4-mini", reasoningEffort: "low" },
  ],
  builder: [
    // Reasoning-capable models listed first for better implementation quality
    { id: "claude-sonnet-4.6", reasoningEffort: "medium" },
    { id: "gpt-5.2", reasoningEffort: "medium" },
    { id: "gpt-5.3-codex", reasoningEffort: "medium" },
    { id: "gpt-5.1-codex", reasoningEffort: "medium" },
    { id: "gpt-5.1", reasoningEffort: "medium" },
    // Non-reasoning fallbacks
    { id: "claude-sonnet-4" },
    { id: "claude-sonnet-4.5" },
  ],
  reasoning: [
    { id: "gpt-5", reasoningEffort: "high" },
    { id: "gpt-5.4", reasoningEffort: "high" },
    { id: "claude-sonnet-4.6", reasoningEffort: "high" },
    { id: "claude-opus-4.5" },
    { id: "claude-opus-4.6" },
    { id: "claude-opus-4.6-1m" },
    { id: "gpt-5.1-codex-max", reasoningEffort: "high" },
  ],
};

// Derived automatically from MODEL_CANDIDATES so it never drifts.
// When you add or remove a model above, this stays correct for free.
export const MODEL_FAMILIES = (() => {
  const claude = new Set();
  const gpt = new Set();
  for (const tier of Object.values(MODEL_CANDIDATES)) {
    for (const { id } of tier) {
      if (id.startsWith("claude")) claude.add(id);
      else if (id.startsWith("gpt")) gpt.add(id);
    }
  }
  return { claude, gpt };
})();

// ---------------------------------------------------------------------------
// Keyword lists
// ---------------------------------------------------------------------------

export const EXPLICIT_REVIEW_KEYWORDS = [
  "review",
  "code review",
  "review this",
  "review the code",
  "review my code",
  "audit",
  "approval readiness",
  "approval readiness checks",
  "approve this",
  "pr review",
  // Bug finding, regression hunting, and approval-readiness are explicit review asks per SKILL.md
  "find bugs",
  "bug finding",
  "regression hunting",
  "regression hunt",
  "find regressions",
];

export const PLAN_KEYWORDS = [
  "plan",
  "design",
  "architecture",
  "architect",
  "proposal",
  "strategy",
  "approach",
];

export const DEBUG_KEYWORDS = [
  "debug",
  "fix",
  "failure",
  "failing",
  "error",
  "crash",
  "root cause",
  "broken",
  "investigate",
];

export const IMPLEMENT_KEYWORDS = [
  "implement",
  "build",
  "create",
  "write",
  "refactor",
  "add",
  "change",
  "update",
  "edit",
  "enhance",
  "modify",
  "adjust",
  "improve",
  "fix the code",
  "fix the formatting",
  "fix the logic",
];

export const LIGHT_KEYWORDS = [
  "explain",
  "summarize",
  "what is",
  "where is",
  "find",
  "list",
  "show",
  "search",
];

export const TOOL_KEYWORDS = [
  "bash",
  "curl",
  "execute",
  "run",
  "tool",
  "api",
  "function",
  "call",
  "invoke",
  "script",
  "command",
  "shell",
  "http",
  "request",
  "endpoint",
  "agent",
];

// Complex multi-tool orchestration patterns warrant reasoning-tier escalation.
// Only multi-word action phrases are included; bare "orchestrate"/"orchestration" caused
// false positives when tasks merely mentioned these concepts in documentation context.
export const ORCHESTRATION_KEYWORDS = [
  "parallel agents",
  "multiple agents",
  "multi-agent",
  "parallel tools",
  "tool chain",
  "chained tools",
];

// ---------------------------------------------------------------------------
// Pure helper functions
// ---------------------------------------------------------------------------

export function getModelFamily(modelId) {
  if (!modelId) return null;
  if (MODEL_FAMILIES.claude.has(modelId)) return "claude";
  if (MODEL_FAMILIES.gpt.has(modelId)) return "gpt";
  return null;
}

export function normalizePrompt(prompt) {
  return String(prompt || "").toLowerCase();
}

// Word-boundary-aware matching prevents false positives like "prefix"→"fix",
// "exchange"→"change", "callback"→"call". Multi-word phrases use substring matching.
export function matchesPattern(text, pattern) {
  if (/\s/.test(pattern)) {
    return text.includes(pattern);
  }
  const escaped = pattern.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  return new RegExp(`\\b${escaped}\\b`).test(text);
}

export function includesAny(text, patterns) {
  return patterns.some((pattern) => matchesPattern(text, pattern));
}

export function isExplicitReviewRequest(text) {
  return includesAny(text, EXPLICIT_REVIEW_KEYWORDS);
}

export function isToolHeavy(text) {
  return includesAny(text, TOOL_KEYWORDS);
}

export function isComplexOrchestration(text) {
  return includesAny(text, ORCHESTRATION_KEYWORDS);
}

export function getComplexity(prompt) {
  const lower = normalizePrompt(prompt);
  const words = lower.trim().split(/\s+/).filter(Boolean).length;
  let score = 0;

  if (words > 40) score += 1;
  if (words > 100) score += 1;
  if (
    includesAny(lower, [
      "multi-file",
      "multiple files",
      "end-to-end",
      "carefully",
      "thorough",
      "deep",
      "complex",
      "large",
      "entire codebase",
    ])
  ) {
    score += 2;
  }

  if (includesAny(lower, PLAN_KEYWORDS) || includesAny(lower, DEBUG_KEYWORDS)) {
    score += 1;
  }

  // File path detection (/.github/, /src/, /lib/, etc.) indicates code changes
  if (/\/[\w-]+\/[\w.-]+/.test(lower)) {
    score += 1;
  }

  if (isToolHeavy(lower)) {
    score += 1;
  }

  return score;
}

export function classifyPrompt(prompt) {
  const lower = normalizePrompt(prompt);
  const complexity = getComplexity(lower);

  if (isExplicitReviewRequest(lower)) {
    return { kind: "review", complexity, tier: "reasoning" };
  }

  if (includesAny(lower, PLAN_KEYWORDS)) {
    return {
      kind: "planning",
      complexity,
      tier: complexity >= 3 ? "reasoning" : "builder",
    };
  }

  if (includesAny(lower, DEBUG_KEYWORDS)) {
    return {
      kind: "debugging",
      complexity,
      tier: complexity >= 3 ? "reasoning" : "builder",
    };
  }

  if (includesAny(lower, IMPLEMENT_KEYWORDS)) {
    let tier = "builder"; // default to builder for all implementation

    // Light-keyword + zero complexity stays in economy
    if (includesAny(lower, LIGHT_KEYWORDS) && complexity === 0) {
      tier = "economy";
    }

    // Escalate for genuine complex orchestration
    if (isComplexOrchestration(lower) && complexity >= 2) {
      tier = "reasoning";
    }

    // Escalate when deeply complex overall
    if (complexity >= 4) {
      tier = "reasoning";
    }

    return {
      kind: "implementation",
      complexity,
      tier,
      toolHeavy: isToolHeavy(lower),
    };
  }

  if (includesAny(lower, LIGHT_KEYWORDS) || complexity === 0) {
    return { kind: "lightweight", complexity, tier: "economy" };
  }

  let generalTier = complexity >= 2 ? "builder" : "economy";
  if (isToolHeavy(lower) && complexity >= 1) generalTier = "builder";
  if (isComplexOrchestration(lower) && complexity >= 2) generalTier = "reasoning";
  return { kind: "general", complexity, tier: generalTier };
}

export function getTierCandidates(route) {
  if (route.kind === "review") {
    return [
      ...MODEL_CANDIDATES.reasoning,
      ...MODEL_CANDIDATES.builder,
      ...MODEL_CANDIDATES.economy,
    ];
  }

  if (route.kind === "planning" || route.kind === "debugging") {
    return route.tier === "reasoning"
      ? [...MODEL_CANDIDATES.reasoning, ...MODEL_CANDIDATES.builder]
      : [...MODEL_CANDIDATES.builder, ...MODEL_CANDIDATES.reasoning, ...MODEL_CANDIDATES.economy];
  }

  if (route.kind === "implementation" || route.kind === "general") {
    return route.tier === "builder"
      ? [...MODEL_CANDIDATES.builder, ...MODEL_CANDIDATES.reasoning, ...MODEL_CANDIDATES.economy]
      : [...MODEL_CANDIDATES.economy, ...MODEL_CANDIDATES.builder, ...MODEL_CANDIDATES.reasoning];
  }

  return [...MODEL_CANDIDATES.economy, ...MODEL_CANDIDATES.builder, ...MODEL_CANDIDATES.reasoning];
}

export function dedupeCandidates(candidates) {
  const seen = new Set();
  return candidates.filter((candidate) => {
    const key = `${candidate.id}:${candidate.reasoningEffort || ""}`;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

export function isSameModelFamily(first, second) {
  if (!first || !second) return false;
  const family = (model) => {
    if (model.startsWith("claude-haiku")) return "claude-haiku";
    if (model.startsWith("claude-sonnet")) return "claude-sonnet";
    if (model.startsWith("claude-opus")) return "claude-opus";
    if (model.includes("codex")) return "codex";
    if (model.startsWith("gpt-5")) return "gpt-5";
    if (model.startsWith("gpt-4.1")) return "gpt-4.1";
    return model;
  };
  return family(first) === family(second);
}

/**
 * Re-order candidates for review diversity: models from a different family
 * than lastImplModel float to the front.
 *
 * Accepts lastImplModel as an explicit parameter (rather than reading module
 * state) so the function stays pure and testable.
 */
export function orderCandidates(candidates, route, lastImplModel = null) {
  if (route.kind !== "review" || !lastImplModel) {
    return candidates;
  }
  return [...candidates].sort((left, right) => {
    const leftSame =
      left.id === lastImplModel ? 2 : isSameModelFamily(left.id, lastImplModel) ? 1 : 0;
    const rightSame =
      right.id === lastImplModel ? 2 : isSameModelFamily(right.id, lastImplModel) ? 1 : 0;
    return leftSame - rightSame; // lower "sameness" score → earlier in list
  });
}

/**
 * Build the additionalContext string surfaced to the agent.
 *
 * lastImplModel is passed explicitly so this stays pure and testable.
 */
export function buildAdditionalContext(decision, currentModelId, lastImplModel = null) {
  const lines = [
    "Model routing policy is active.",
    `Current task class: ${decision.kind}.`,
    `Selected model for this turn: ${decision.selectedModelId || currentModelId || "unchanged-current-model"}.`,
  ];

  if (decision.reasoningEffort) {
    lines.push(`Reasoning effort: ${decision.reasoningEffort}.`);
  }

  if (decision.kind === "review" && lastImplModel) {
    lines.push(`Prefer review diversity versus implementation model ${lastImplModel}.`);
    if (decision.selectedModelId === lastImplModel) {
      lines.push(
        "A distinct review model was not available, so the router fell back to the current best option.",
      );
    }
  }

  if (decision.kind === "lightweight") {
    lines.push("Keep the solution lean and avoid premium-model depth unless the task expands.");
  }

  if (
    (decision.kind === "implementation" || decision.kind === "general") &&
    decision.complexity <= 2
  ) {
    lines.push(
      "Inspect only the most relevant file(s). Implement directly without extensive planning.",
    );
  }

  if (decision.kind === "planning" || decision.kind === "debugging") {
    lines.push("Favor strong reasoning and structured analysis before acting.");
  }

  return lines.join(" ");
}

import { joinSession } from "@github/copilot-sdk/extension";
import {
  MODEL_CANDIDATES,
  getModelFamily,
  normalizePrompt,
  includesAny,
  classifyPrompt,
  getTierCandidates,
  dedupeCandidates,
  orderCandidates,
  buildAdditionalContext,
} from "./policy.mjs";

// ---------------------------------------------------------------------------
// Session-level state
// ---------------------------------------------------------------------------

let lastImplementationModel = null;
let lastReviewModel = null;
let lastDecision = null;

// Confusion detection: tracks signs the agent may be stuck or looping.
// Err on the side of patience — especially when the agent is in active thinking
// (reasoning display enabled) — and only swap after multiple strong signals.
const confusionMetrics = {
  turnCount: 0,
  recentMessages: [], // last N agent messages for loop detection
  errorCount: 0,
  repeatedPatternCount: 0,
  lastSwitchTurn: -999, // turn when we last switched due to confusion
  currentModelFamily: null,
};

const CONFUSION_THRESHOLDS = {
  minTurnsSinceLastSwitch: 5,
  maxRecentMessagesTracked: 8,
  repeatingPatternThreshold: 3,
  consecutiveErrorThreshold: 2,
  similarityThreshold: 0.75,
};

// ---------------------------------------------------------------------------
// Confusion detection helpers (stateful — stay in this file)
// ---------------------------------------------------------------------------

function calculateSimilarity(text1, text2) {
  const words1 = new Set(
    normalizePrompt(text1)
      .split(/\s+/)
      .filter((w) => w.length > 3),
  );
  const words2 = new Set(
    normalizePrompt(text2)
      .split(/\s+/)
      .filter((w) => w.length > 3),
  );
  if (words1.size === 0 || words2.size === 0) return 0;
  const intersection = [...words1].filter((w) => words2.has(w)).length;
  const union = new Set([...words1, ...words2]).size;
  return union > 0 ? intersection / union : 0;
}

function detectConfusionSignals(message) {
  const text = normalizePrompt(message);
  const signals = [];

  const confusedPhrases = [
    "i'm not sure",
    "i'm confused",
    "unclear",
    "not clear",
    "i don't",
    "cannot proceed",
    "stuck",
    "unable to",
    "let me try",
    "let me re-attempt",
  ];
  if (includesAny(text, confusedPhrases)) signals.push("agent-confusion-acknowledgment");

  if (text.split(/\s+/).length < 10) signals.push("very-short-response");

  if (
    includesAny(text, ["can you", "could you", "would you", "please", "more details", "clarify"])
  ) {
    if ((text.match(/\?/g) || []).length > 2) signals.push("repetitive-asking");
  }

  if (text.includes("but earlier") || text.includes("wait,") || text.includes("i was wrong")) {
    signals.push("self-contradiction");
  }

  return signals;
}

function detectLoopingBehavior() {
  if (confusionMetrics.recentMessages.length < 3) return false;
  let similarPairs = 0;
  for (let i = confusionMetrics.recentMessages.length - 1; i > 0; i--) {
    if (
      calculateSimilarity(
        confusionMetrics.recentMessages[i],
        confusionMetrics.recentMessages[i - 1],
      ) > CONFUSION_THRESHOLDS.similarityThreshold
    ) {
      similarPairs++;
    }
  }
  return similarPairs >= 2;
}

async function getAlternateModel(session, currentModelId) {
  const currentFamily = getModelFamily(currentModelId);
  const targetFamily = currentFamily === "claude" ? "gpt" : "claude";

  let currentTier = null;
  for (const [tier, models] of Object.entries(MODEL_CANDIDATES)) {
    if (models.some((m) => m.id === currentModelId)) {
      currentTier = tier;
      break;
    }
  }
  if (!currentTier) return null;

  const tierCandidates = MODEL_CANDIDATES[currentTier] || [];
  const candidates = tierCandidates.filter((m) => getModelFamily(m.id) === targetFamily);

  // If tier exhausted in alternate family, try next tier up
  if (candidates.length === 0 && currentTier === "economy") {
    return (
      (MODEL_CANDIDATES.builder || []).find((m) => getModelFamily(m.id) === targetFamily) || null
    );
  }
  if (candidates.length === 0 && currentTier === "builder") {
    return (
      (MODEL_CANDIDATES.reasoning || []).find((m) => getModelFamily(m.id) === targetFamily) || null
    );
  }

  return candidates[0] || null;
}

async function considerConfusionSwap(session, currentModelId) {
  const turnsSinceSwitch = confusionMetrics.turnCount - confusionMetrics.lastSwitchTurn;
  if (turnsSinceSwitch < CONFUSION_THRESHOLDS.minTurnsSinceLastSwitch) return null;

  const isLooping = detectLoopingBehavior();
  const hasHighErrorRate =
    confusionMetrics.errorCount >= CONFUSION_THRESHOLDS.consecutiveErrorThreshold;

  // Only swap with solid evidence (looping + errors)
  if (!(isLooping && hasHighErrorRate)) return null;

  return getAlternateModel(session, currentModelId);
}

async function maybeSwapDueToConfusion(session, currentModelId) {
  const alternate = await considerConfusionSwap(session, currentModelId);
  if (!alternate) return null;

  try {
    await session.rpc.model.switchTo({
      modelId: alternate.id,
      reasoningEffort: alternate.reasoningEffort,
    });
    confusionMetrics.lastSwitchTurn = confusionMetrics.turnCount;
    confusionMetrics.errorCount = 0;
    await session.log(
      `model-router: Detected confusion/looping. Swapping from ${currentModelId} to ${alternate.id} (alternate family).`,
      { ephemeral: true },
    );
    return alternate;
  } catch {
    return null;
  }
}

// ---------------------------------------------------------------------------
// Model switching
// ---------------------------------------------------------------------------

async function trySwitchModel(session, route, currentModelId) {
  let candidates = orderCandidates(
    dedupeCandidates(getTierCandidates(route)),
    route,
    lastImplementationModel,
  );

  // For moderate-complexity builder tasks, try a same-model reasoning downgrade first
  if (
    (route.kind === "implementation" || route.kind === "general") &&
    route.tier === "builder" &&
    route.complexity <= 2 &&
    currentModelId
  ) {
    try {
      await session.rpc.model.switchTo({ modelId: currentModelId, reasoningEffort: "low" });
      return { id: currentModelId, reasoningEffort: "low" };
    } catch {
      // fall through to full model switching
    }
  }

  if (currentModelId) {
    candidates = candidates.filter((c) => c.id !== currentModelId);
  }

  // Review diversity: exclude last implementation model even when getCurrent() fails
  if (route.kind === "review" && lastImplementationModel) {
    candidates = candidates.filter((c) => c.id !== lastImplementationModel);
  }

  let selected = null;
  for (const candidate of candidates) {
    try {
      await session.rpc.model.switchTo({
        modelId: candidate.id,
        reasoningEffort: candidate.reasoningEffort,
      });
      selected = candidate;
      break;
    } catch {
      continue;
    }
  }

  return selected || { id: currentModelId || null, reasoningEffort: null };
}

// ---------------------------------------------------------------------------
// Session
// ---------------------------------------------------------------------------

const session = await joinSession({
  hooks: {
    onSessionStart: async () => {
      confusionMetrics.turnCount = 0;
      confusionMetrics.recentMessages = [];
      confusionMetrics.errorCount = 0;
      confusionMetrics.lastSwitchTurn = -999;
      await session.log("model-router loaded", { ephemeral: true });
      return {
        additionalContext:
          "The model-router extension is available. Favor the lowest-cost viable model and prefer a different model for review than implementation when possible.",
      };
    },

    onUserPromptSubmitted: async (input) => {
      confusionMetrics.turnCount++;
      const route = classifyPrompt(input.prompt);
      const current = await session.rpc.model.getCurrent().catch(() => ({ modelId: undefined }));
      const chosen = await trySwitchModel(session, route, current.modelId);

      if (route.kind === "implementation" || route.kind === "debugging") {
        lastImplementationModel = chosen.id || current.modelId || lastImplementationModel;
      }
      if (route.kind === "review") {
        lastReviewModel = chosen.id || current.modelId || lastReviewModel;
      }

      lastDecision = {
        kind: route.kind,
        complexity: route.complexity,
        selectedModelId: chosen.id || current.modelId || null,
        reasoningEffort: chosen.reasoningEffort || null,
      };

      await session.log(
        `model-router: ${route.kind} -> ${lastDecision.selectedModelId || "current model"}`,
        { ephemeral: true },
      );

      return {
        additionalContext: buildAdditionalContext(lastDecision, current.modelId, lastImplementationModel),
      };
    },

    onAgentMessage: async (message) => {
      const msgText = String(message.content || "");
      if (msgText.length > 0) {
        confusionMetrics.recentMessages.push(msgText);
        if (
          confusionMetrics.recentMessages.length > CONFUSION_THRESHOLDS.maxRecentMessagesTracked
        ) {
          confusionMetrics.recentMessages.shift();
        }
      }

      const signals = detectConfusionSignals(msgText);
      if (signals.length > 0) confusionMetrics.repeatedPatternCount++;

      const current = await session.rpc.model.getCurrent().catch(() => ({ modelId: undefined }));
      if (current.modelId) {
        const alternate = await maybeSwapDueToConfusion(session, current.modelId);
        if (alternate) confusionMetrics.currentModelFamily = getModelFamily(alternate.id);
      }
    },

    onError: async () => {
      confusionMetrics.errorCount++;
      if (confusionMetrics.errorCount >= CONFUSION_THRESHOLDS.consecutiveErrorThreshold) {
        const current = await session.rpc.model.getCurrent().catch(() => ({ modelId: undefined }));
        if (current.modelId) await maybeSwapDueToConfusion(session, current.modelId);
      }
    },
  },

  tools: [
    {
      name: "model_router_status",
      description:
        "Show the current model-router decision state and confusion metrics for this Copilot CLI session.",
      parameters: { type: "object", properties: {} },
      handler: async () => {
        const current = await session.rpc.model
          .getCurrent()
          .catch(() => ({ modelId: undefined }));
        const isLooping = detectLoopingBehavior();
        return JSON.stringify(
          {
            // Quick-glance summary for local debugging
            debug: {
              activeModel: current.modelId || null,
              lastImplModel: lastImplementationModel,
              looping: isLooping,
              errorCount: confusionMetrics.errorCount,
              repeatedPatternCount: confusionMetrics.repeatedPatternCount,
            },
            currentModel: current.modelId || null,
            lastImplementationModel,
            lastReviewModel,
            lastDecision,
            confusionMetrics: {
              turnCount: confusionMetrics.turnCount,
              recentMessageCount: confusionMetrics.recentMessages.length,
              errorCount: confusionMetrics.errorCount,
              repeatedPatternCount: confusionMetrics.repeatedPatternCount,
              turnsSinceLastConfusionSwitch:
                confusionMetrics.turnCount - confusionMetrics.lastSwitchTurn,
              isLooping,
            },
          },
          null,
          2,
        );
      },
    },
  ],
});

/**
 * Regression tests for the shared routing policy module.
 *
 * Run with: node --test tests/routing-policy.test.mjs
 *
 * No external dependencies — uses Node's built-in test runner and assert.
 */

import { strict as assert } from "node:assert";
import { describe, it } from "node:test";
import {
  MODEL_CANDIDATES,
  MODEL_FAMILIES,
  classifyPrompt,
  getTierCandidates,
  getComplexity,
  dedupeCandidates,
  orderCandidates,
  getModelFamily,
  isSameModelFamily,
  buildAdditionalContext,
  isExplicitReviewRequest,
  isComplexOrchestration,
} from "../.github/extensions/model-router/policy.mjs";

// ---------------------------------------------------------------------------
// MODEL_FAMILIES consistency with MODEL_CANDIDATES
// ---------------------------------------------------------------------------

describe("MODEL_FAMILIES", () => {
  it("every model in MODEL_CANDIDATES appears in MODEL_FAMILIES", () => {
    const familyIds = new Set([...MODEL_FAMILIES.claude, ...MODEL_FAMILIES.gpt]);
    for (const [tier, models] of Object.entries(MODEL_CANDIDATES)) {
      for (const { id } of models) {
        assert.ok(familyIds.has(id), `Model "${id}" (${tier} tier) is missing from MODEL_FAMILIES`);
      }
    }
  });

  it("MODEL_FAMILIES contains no IDs absent from MODEL_CANDIDATES", () => {
    const candidateIds = new Set(
      Object.values(MODEL_CANDIDATES)
        .flat()
        .map((m) => m.id),
    );
    for (const id of [...MODEL_FAMILIES.claude, ...MODEL_FAMILIES.gpt]) {
      assert.ok(candidateIds.has(id), `MODEL_FAMILIES has stale ID "${id}" not in MODEL_CANDIDATES`);
    }
  });

  it("claude family contains only claude-prefixed IDs", () => {
    for (const id of MODEL_FAMILIES.claude) {
      assert.ok(id.startsWith("claude"), `Expected claude prefix: "${id}"`);
    }
  });

  it("gpt family contains only gpt-prefixed IDs", () => {
    for (const id of MODEL_FAMILIES.gpt) {
      assert.ok(id.startsWith("gpt"), `Expected gpt prefix: "${id}"`);
    }
  });

  it("claude and gpt families are disjoint", () => {
    for (const id of MODEL_FAMILIES.claude) {
      assert.ok(
        !MODEL_FAMILIES.gpt.has(id),
        `"${id}" appears in both claude and gpt families`,
      );
    }
  });
});

