});

// ---------------------------------------------------------------------------
// classifyPrompt
// ---------------------------------------------------------------------------

describe("classifyPrompt", () => {
  it("routes short factual question to lightweight/economy", () => {
    const r = classifyPrompt("What does this function do?");
    assert.equal(r.kind, "lightweight");
    assert.equal(r.tier, "economy");
  });

  it("routes 'review' to reasoning tier", () => {
    const r = classifyPrompt("Review my PR for security issues");
    assert.equal(r.kind, "review");
    assert.equal(r.tier, "reasoning");
  });

  it("routes 'audit' to review/reasoning", () => {
    const r = classifyPrompt("Audit this code");
    assert.equal(r.kind, "review");
    assert.equal(r.tier, "reasoning");
  });

  it("routes 'find bugs' to review/reasoning", () => {
    const r = classifyPrompt("Find bugs in this module");
    assert.equal(r.kind, "review");
    assert.equal(r.tier, "reasoning");
  });

  it("routes implementation to builder tier by default", () => {
    const r = classifyPrompt("Implement a login form");
    assert.equal(r.kind, "implementation");
    assert.equal(r.tier, "builder");
  });

  it("routes simple plan to builder (low complexity)", () => {
    const r = classifyPrompt("Design a simple API");
    assert.equal(r.kind, "planning");
    assert.equal(r.tier, "builder");
  });

  it("routes debug prompt to builder (low complexity)", () => {
    const r = classifyPrompt("Debug this error");
    assert.equal(r.kind, "debugging");
    assert.equal(r.tier, "builder");
  });

  it("escalates complex orchestration to reasoning", () => {
    const r = classifyPrompt(
      "Implement a multi-agent system with chained tools and parallel agents to process data end-to-end carefully",
    );
    assert.equal(r.tier, "reasoning");
  });

  it("escalates high-complexity implementation to reasoning", () => {
    // complexity >= 4 triggers reasoning escalation
    const r = classifyPrompt(
      "Carefully refactor the entire codebase across multiple files with thorough end-to-end testing and complex error handling",
    );
    assert.equal(r.tier, "reasoning");
  });

  it("treats bare 'bug' mention in implementation as builder, not review", () => {
    // Generic "bug" should NOT trigger review mode (only explicit phrases like "find bugs")
    const r = classifyPrompt("Fix the bug in the login function");
    assert.equal(r.kind, "debugging");
    assert.notEqual(r.kind, "review");
  });
});

// ---------------------------------------------------------------------------
// getComplexity
// ---------------------------------------------------------------------------

describe("getComplexity", () => {
  it("returns 0 for a short simple prompt", () => {
    assert.equal(getComplexity("What is this?"), 0);
  });

  it("adds score for prompts longer than 40 words", () => {
    const longPrompt = "word ".repeat(45).trim();
    assert.ok(getComplexity(longPrompt) >= 1);
  });

  it("adds 2 for complexity keywords like 'carefully' or 'entire codebase'", () => {
    assert.ok(getComplexity("carefully refactor the entire codebase") >= 2);
  });

  it("adds score for tool keywords", () => {
    const base = getComplexity("make a change");
    const withTool = getComplexity("make a change using bash");
    assert.ok(withTool > base);
  });

  it("adds score for plan/debug keywords", () => {
    const base = getComplexity("write a thing");
    const withDebug = getComplexity("debug a thing");
    assert.ok(withDebug > base);
  });
});

