describe("getTierCandidates", () => {
  it("review route lists reasoning candidates first", () => {
    const candidates = getTierCandidates({ kind: "review", tier: "reasoning" });
    const reasoningIds = new Set(MODEL_CANDIDATES.reasoning.map((m) => m.id));
    assert.ok(
      reasoningIds.has(candidates[0].id),
      "First candidate should come from reasoning tier",
    );
  });

  it("lightweight route lists economy candidates first", () => {
    const candidates = getTierCandidates({ kind: "lightweight", tier: "economy" });
    const economyIds = new Set(MODEL_CANDIDATES.economy.map((m) => m.id));
    assert.ok(economyIds.has(candidates[0].id), "First candidate should come from economy tier");
  });

  it("builder implementation route lists builder candidates first", () => {
    const candidates = getTierCandidates({ kind: "implementation", tier: "builder" });
    const builderIds = new Set(MODEL_CANDIDATES.builder.map((m) => m.id));
    assert.ok(builderIds.has(candidates[0].id), "First candidate should come from builder tier");
  });

  it("review route includes all tiers", () => {
    const candidates = getTierCandidates({ kind: "review", tier: "reasoning" });
    const allIds = new Set(candidates.map((m) => m.id));
    for (const tier of Object.values(MODEL_CANDIDATES)) {
      for (const { id } of tier) {
        // claude-sonnet-4.6 appears in builder AND reasoning; presence check is by id only
        assert.ok(allIds.has(id), `Expected "${id}" to appear in review candidate list`);
      }
    }
  });
});

// ---------------------------------------------------------------------------
// dedupeCandidates
// ---------------------------------------------------------------------------

describe("dedupeCandidates", () => {
  it("removes exact duplicate (id + reasoningEffort) entries", () => {
    const input = [
      { id: "gpt-5", reasoningEffort: "high" },
      { id: "gpt-5", reasoningEffort: "high" },
      { id: "gpt-5", reasoningEffort: "low" },
    ];
    assert.equal(dedupeCandidates(input).length, 2);
  });

  it("keeps entries with same id but different reasoningEffort", () => {
    const input = [
      { id: "claude-sonnet-4.6", reasoningEffort: "medium" },
      { id: "claude-sonnet-4.6", reasoningEffort: "high" },
    ];
    assert.equal(dedupeCandidates(input).length, 2);
  });

  it("preserves order of first occurrence", () => {
    const input = [
      { id: "gpt-5" },
      { id: "claude-haiku-4.5" },
      { id: "gpt-5" },
    ];
    const result = dedupeCandidates(input);
    assert.equal(result[0].id, "gpt-5");
    assert.equal(result[1].id, "claude-haiku-4.5");
  });
});

// ---------------------------------------------------------------------------
// orderCandidates — review diversity
// ---------------------------------------------------------------------------

describe("orderCandidates", () => {
  const candidates = [
    { id: "gpt-5", reasoningEffort: "high" },
    { id: "claude-sonnet-4.6", reasoningEffort: "high" },
    { id: "claude-opus-4.6" },
  ];
  const reviewRoute = { kind: "review", tier: "reasoning" };

  it("moves same-family models to the back for review", () => {
    // last impl was claude → GPT candidates should sort first
    const ordered = orderCandidates(candidates, reviewRoute, "claude-opus-4.5");
    assert.equal(ordered[0].id, "gpt-5", "GPT model should be first when last impl was Claude");
  });

  it("does not reorder when route is not review", () => {
    const ordered = orderCandidates(
      candidates,
      { kind: "implementation", tier: "builder" },
      "claude-opus-4.5",
    );
    assert.equal(ordered[0].id, candidates[0].id, "Should preserve order for non-review");
  });

  it("does not reorder when lastImplModel is null", () => {
    const ordered = orderCandidates(candidates, reviewRoute, null);
    assert.deepEqual(ordered, candidates);
  });

  it("pushes exact last-impl model to the very back", () => {
    const ordered = orderCandidates(candidates, reviewRoute, "gpt-5");
    assert.equal(
      ordered[ordered.length - 1].id,
      "gpt-5",
      "Exact last-impl model should be last",
    );
  });
});

