describe("isSameModelFamily", () => {
  it("returns true for two claude-sonnet models", () =>
    assert.equal(isSameModelFamily("claude-sonnet-4", "claude-sonnet-4.5"), true));
  it("returns true for two claude-opus models", () =>
    assert.equal(isSameModelFamily("claude-opus-4.5", "claude-opus-4.6"), true));
  it("returns true for two gpt-5 models", () =>
    assert.equal(isSameModelFamily("gpt-5", "gpt-5.4"), true));
  it("returns false for claude-sonnet and claude-opus", () =>
    assert.equal(isSameModelFamily("claude-sonnet-4", "claude-opus-4.5"), false));
  it("returns false for claude and gpt", () =>
    assert.equal(isSameModelFamily("claude-sonnet-4", "gpt-5"), false));
  it("returns false for null input", () =>
    assert.equal(isSameModelFamily(null, "gpt-5"), false));
});

