describe("isExplicitReviewRequest", () => {
  it("matches 'review'", () => assert.ok(isExplicitReviewRequest("please review this code")));
  it("matches 'audit'", () => assert.ok(isExplicitReviewRequest("audit my implementation")));
  it("matches 'find bugs'", () => assert.ok(isExplicitReviewRequest("find bugs in auth.js")));
